// 慢车 持续时间60s
// 下载状态，上传低于200kb，进度在10-100之间
// 下载人数大于100的种子不删
// 0点-7点，或者客户端下载种子数量小于等于10时不删种
(maindata, torrent) => {
  const categoryList = ["不删"];
  const { state, upspeed, progress, ratio, category } = torrent.originProp;
  if (categoryList.indexOf(category) !== -1 || torrent.leecher >= 100) {
    return false;
  }
  if (
    (moment().hour() >= 0 && moment().hour() <= 7) ||
    maindata.leechingCount <= 15
  ) {
    return false;
  }
  if (
    state === "downloading" &&
    upspeed <= util.calSize(200, "KiB") &&
    moment().unix() - torrent.addedTime >= 600
  ) {
    return true;
  }
  return false;
};
